class Solution {
    public int shortestMatchingSubstring(String s, String p) {
        int m = p.length();
        int n = s.length();
        int[][] dp = new int[m + 1][n + 1];

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (p.charAt(i - 1) == '*') {
                    dp[i][j] = Math.min(dp[i - 1][j], dp[i - 1][j - s.charAt(j - 1) == '*' ? 1 : 0);
                } else {
                    dp[i][j] = dp[i - 1][j] + 1;
                }
            }
        }
        return dp[m][n];
    }
}
